import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const AddCategory = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: "",
    color: "#8b5cf6" // default violet
  });

  // 🔹 preset colors
  const presetColors = [
    "#8b5cf6", // violet
    "#3b82f6", // blue
    "#22c55e", // green
    "#ef4444", // red
    "#eab308", // yellow
    "#f97316"  // orange
  ];

  // 🔹 handle input
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔹 select preset color
  const handleColorSelect = (color) => {
    setForm({ ...form, color });
  };

  // 🔹 submit
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!form.name.trim()) {
      alert("Category name required ❌");
      return;
    }

    const existing =
      JSON.parse(localStorage.getItem("categories")) || [];

    const updated = [...existing, form.name];

    localStorage.setItem("categories", JSON.stringify(updated));

    alert("Category Created ✅");
    navigate(-1);
  };

  return (
    <div className="min-h-screen bg-[#2d3561] text-white flex flex-col items-center p-6">

      {/* 🔙 Back */}
      <div className="w-full max-w-2xl">
        <button onClick={() => navigate(-1)} className="text-xl mb-4">
          ←
        </button>
      </div>

      <h2 className="text-3xl font-bold mb-6">Add Category</h2>

      <form onSubmit={handleSubmit} className="w-full max-w-xl space-y-6">

        {/* Category Name */}
        <input
          type="text"
          name="name"
          placeholder="Category name *"
          value={form.name}
          onChange={handleChange}
          required
          className="w-full px-4 py-4 rounded-2xl bg-white/10 border border-white/20 outline-none"
        />

        {/* 🔥 Color Picker Box */}
        <div className="w-full p-4 rounded-2xl bg-white/10 border border-white/20 space-y-4">

          <p className="text-sm text-white/70">Select Color</p>

          {/* Preset Colors */}
          <div className="flex gap-3 flex-wrap">
            {presetColors.map((color, i) => (
              <div
                key={i}
                onClick={() => handleColorSelect(color)}
                className={`w-10 h-10 rounded-full cursor-pointer border-2 ${
                  form.color === color
                    ? "border-white scale-110"
                    : "border-transparent"
                }`}
                style={{ backgroundColor: color }}
              />
            ))}
          </div>

          {/* Custom Color Picker */}
          <div className="flex items-center gap-3">

            <input
              type="color"
              value={form.color}
              onChange={(e) =>
                setForm({ ...form, color: e.target.value })
              }
              className="w-12 h-12 rounded cursor-pointer border-none"
            />

            <input
              type="text"
              value={form.color}
              onChange={(e) =>
                setForm({ ...form, color: e.target.value })
              }
              placeholder="#ffffff"
              className="flex-1 px-3 py-2 rounded bg-white/10 border border-white/20 outline-none text-white"
            />
          </div>

        </div>

        {/* Button */}
        <button
          type="submit"
          className="w-full py-4 rounded-full bg-gradient-to-r from-purple-500 to-pink-500 text-white text-xl font-semibold hover:scale-105 transition"
        >
          Create Category
        </button>

      </form>
    </div>
  );
};

export default AddCategory;
